#!/usr/bin/env python3
"""apply-consolidation.py - Run from project root: python3 apply-consolidation.py"""
import base64, os, re, shutil
from datetime import datetime

ts = datetime.now().strftime("%Y%m%d-%H%M%S")
BACKUP = "backups/consolidation-" + ts
os.makedirs(BACKUP, exist_ok=True)

INPUTS_B64 = ""

# Step 1: Write inputs.tsx
INPUTS_PATH = "client/src/pages/modeling/projects/workspace/inputs.tsx"
if os.path.exists(INPUTS_PATH):
    shutil.copy2(INPUTS_PATH, os.path.join(BACKUP, "inputs.tsx.bak"))
    print("Backed up " + INPUTS_PATH)
decoded = base64.b64decode(INPUTS_B64)
with open(INPUTS_PATH, "wb") as f:
    f.write(decoded)
print("Wrote consolidated inputs.tsx (" + str(len(decoded)) + " bytes)")

# Step 2: Patch historical-pl.tsx
HPL = "client/src/pages/modeling/projects/workspace/historical-pl.tsx"
if os.path.exists(HPL):
    shutil.copy2(HPL, os.path.join(BACKUP, "historical-pl.tsx.bak"))
    with open(HPL, "r") as f:
        c = f.read()
    orig = c
    c = c.replace(
        "import { PLModeToggle, PLBuilder } from '@/components/modeling/pl-mode-toggle';",
        "// PLModeToggle moved to Inputs tab (Session 4)"
    )
    c = c.replace(
        "import { DirectInputForm } from '@/components/modeling/direct-input-form';",
        "// DirectInputForm moved to Inputs tab (Session 4)"
    )
    # Remove PLModeToggle JSX render block
    c = re.sub(
        r'\n\s*\{project && \(\n\s*<PLModeToggle\n\s*project=\{project\}\n\s*onModeChange=\{\(\) => \{\n\s*queryClient\.invalidateQueries.*?/>\n\s*\)\}',
        '', c, flags=re.DOTALL
    )
    # Remove DirectInputForm JSX render block
    c = re.sub(
        r"""\n\s*\{project && \(\(project as any\)\.modelInputMode === 'direct_input' \|\| \(project as any\)\.modelInputMode === 'hybrid'\) && \(\n\s*<DirectInputForm project=\{project\} />\n\s*\)\}""",
        '', c, flags=re.DOTALL
    )
    c = c.replace('  // Fetch project for PLModeToggle', '  // Fetch project data')
    if c != orig:
        with open(HPL, "w") as f:
            f.write(c)
        rem = c.count("<PLModeToggle") + c.count("<DirectInputForm")
        print("Patched " + HPL)
        if rem > 0:
            print("  WARNING: " + str(rem) + " JSX refs remain")
    else:
        print("No changes to historical-pl.tsx")
else:
    print(HPL + " not found")

print("\nDONE. Run: npm run build")
